-- Delete the bad combined row
DELETE FROM sku_new_override WHERE style = 'NESTA' AND colour = 'VANILLA VINTAGE';
-- Insert the correct row with colour=VANILLA, leather=VINTAGE
INSERT INTO sku_new_override (style, colour, leather, isNew)
VALUES ('NESTA', 'VANILLA', 'VINTAGE', 0)
ON DUPLICATE KEY UPDATE isNew = 0;
-- Verify
SELECT style, colour, leather, isNew FROM sku_new_override WHERE style = 'NESTA';

